INSERT INTO `app_graphics` VALUES
('217B2C08CE2FFF6F1B1C7444BDA6BD7F','Número de entidades por módulo','2025-04-11 18:19:28','2026-03-25 09:01:05','D15D4315C5B64BB2E6E17E0A4EBEB319','pie','select id_module, module, count(0) as entidades , -1 as uno\r\nfrom app_entities as e\r\nleft join app_modules as m on e.id_module = m.id\r\ngroup by module\r\n\r\n','2 desc','entidades','module'),
('DFE5BC48B3F67F94DA3CDCC42D0B90CD','Numero columnas por tabla','2025-04-12 17:43:37','2026-03-25 09:00:22','D15D4315C5B64BB2E6E17E0A4EBEB319','bar','select e.id_module as id_module,  e.entity, count(0) as num_columnas, rand()*10 as otro\r\nfrom app_entities e\r\ninner join app_entity_columns c on e.id = c.id_entity \r\ngroup by id_module, entity','3 desc','num_columnas, otro','entity'),
('FBCD4ABD9823A4AA97BBB9CE07510C12','Ofertas de la cuenta por estado','2026-03-26 15:45:41','2026-06-17 11:42:25','490484A9474D03AB69738B7FC05D057C','bar','select id_cuenta, estado, sum(total_neto) as importe , op.descripcion\r\nfrom ventas_ofertas ofe\r\ninner join app_optionsets op on ofe.estado = op.codigo and op.dominio = \'ESTADO_OFERTA\'\r\ngroup by id_cuenta, estado,op.descripcion','estado ','importe','descripcion');
