INSERT INTO `app_plugin_library` VALUES
('744C7174AA8C8A2410BA94C933C62067','recurso.html','2025-10-19 17:58:24','2026-06-12 13:21:01',1,'2BAA56D57128A664AD18DF268E31E49E','<!DOCTYPE html>\r\n<html lang=\"es\">\r\n<head>\r\n  <meta charset=\"UTF-8\">\r\n  <title>Procesar CSV y convertir a JSON</title>\r\n\r\n  <script>\r\n      \r\n    document.addEventListener(\"DOMContentLoaded\", onload);\r\n    function onload(){\r\n        debugger;\r\n        let app = window.parent.MyApp;\r\n        let id = app.form.getFieldValue(\"id\");\r\n        app.ui.notify(id);\r\n    }\r\n  </script>\r\n</head>\r\n<body>\r\n  <?php echo \"hola mundo\"; ?>\r\n  <button type=\"button\" class=\"btn btn-primary\" onclick=\"window.parent.reloadPage();\">Primary</button>\r\n  \r\n</body>\r\n</html>\r\n'),
('C51F112FEA4A404BA9970F5593E384EA','ventas_lib.php','2025-05-06 10:07:26','2026-06-19 12:14:47',1,'2BAA56D57128A664AD18DF268E31E49E','<?php\r\n\r\n\r\nclass BL_Ventas {\r\n    \r\n    public static function getMapping_Quote2Order(){\r\n        $map = new Mapping();\r\n        \r\n        $map->addMapping(\'titulo\', \'titulo\');\r\n        $map->addMapping(\'total_neto\', \'total_neto\');\r\n        $map->addMapping(\'importe_total\', \'importe_total\');\r\n        $map->addMapping(\'id_cuenta\', \'id_cuenta\');\r\n        $map->addMapping(\'notas\', \'notas\');\r\n        $map->addMapping(\'id\', \'id_oferta\');\r\n        $map->addMapping(\'total_impuestos\', \'total_impuestos\');\r\n        $map->addMapping(\'id_empresa\', \'id_empresa\');\r\n        return $map;\r\n\r\n    }\r\n    public static function getMapping_QuoteLine2OrderLine(){\r\n        $map = new Mapping();\r\n        \r\n        $map->addMapping(\'cantidad\');\r\n        $map->addMapping(\'Concepto\');\r\n        $map->addMapping(\'descuento\');\r\n        $map->addMapping(\'id_producto\');\r\n        $map->addMapping(\'impuesto\');\r\n        $map->addMapping(\'impuestos\');\r\n        $map->addMapping(\'orden\');\r\n        $map->addMapping(\'precio\');\r\n        $map->addMapping(\'status\');\r\n        $map->addMapping(\'total_impuestos\');\r\n        $map->addMapping(\'total_linea\');\r\n        $map->addMapping(\'total_neto\');\r\n\r\n        \r\n        return $map;\r\n\r\n    }\r\n    \r\n    public static function Confirmar_Oferta($id_oferta){\r\n        \r\n        $map = BL_Ventas::getMapping_Quote2Order();\r\n        $map_linea = BL_Ventas::getMapping_QuoteLine2OrderLine();\r\n        \r\n        $row = dbgetbyid(\"ventas_ofertas\",$id_oferta);\r\n        \r\n        $pedido = $map->cloneRecord($row);\r\n        $pedido[\'codigo\'] = nextSequence(\"ventas_pedidos\");\r\n        $pedido[\'fecha_pedido\']= date(\"Y-m-d\");\r\n        $pedido[\'status\']= 1;\r\n        \r\n        \r\n        $id_pedido = dbinsert(\"ventas_pedidos\",$pedido);\r\n        \r\n        $lineas = query(\"Select * from ventas_ofertas_lineas where id_oferta = \'$id_oferta\'\");\r\n        \r\n        foreach ($lineas as $linea){\r\n            \r\n            $new_record = $map_linea->cloneRecord($linea);\r\n            $new_record[\'id_pedido\'] = $id_pedido;\r\n            $new_record[\'status\']= 1;\r\n            \r\n            dbinsert(\"ventas_pedidos_lineas\",$new_record);\r\n            \r\n        }\r\n        \r\n        \r\n        \r\n    }\r\n    \r\n}\r\n\r\n'),
('F60803B70C817BC17F4FA11BE3876C97','codigo_barras.html','2026-06-12 13:15:02','2026-06-15 11:23:09',1,'2BAA56D57128A664AD18DF268E31E49E','<!DOCTYPE html>\r\n<html lang=\"es\">\r\n<head>\r\n  <meta charset=\"UTF-8\">\r\n  <title>Leer códigos de barras con cámara</title>\r\n\r\n  <script src=\"https://unpkg.com/html5-qrcode@2.3.8/html5-qrcode.min.js\" type=\"text/javascript\"></script>\r\n  \r\n  <script type=\"text/javascript\">\r\n    document.addEventListener(\"DOMContentLoaded\", onload);\r\n\r\n\r\n    function onload(){\r\n        \r\n        debugger;\r\n        function onScanSuccess(decodedText, decodedResult) {\r\n        // handle the scanned code as you like, for example:\r\n            alert(`Code matched = ${decodedText}`);\r\n        }\r\n        \r\n        function onScanFailure(error) {\r\n        // handle scan failure, usually better to ignore and keep scanning.\r\n        // for example:\r\n            console.warn(`Code scan error = ${error}`);\r\n        }\r\n        \r\n        \r\n        const reader = document.getElementById(\"reader\");\r\n\r\n        const size = Math.min(\r\n            reader.clientWidth,\r\n            window.innerHeight\r\n        ) * 0.7;\r\n        \r\n        let html5QrcodeScanner = new Html5QrcodeScanner(\r\n            \"reader\",\r\n            { fps: 1000, qrbox: {width: size, height: size} },\r\n            /* verbose= */ false);\r\n        html5QrcodeScanner.render(onScanSuccess, onScanFailure);\r\n        \r\n    }\r\n    \r\n    \r\n    \r\n</script>\r\n</head>\r\n<body>\r\n  \r\n  <div id=\"reader\" ></div>\r\n  \r\n  <script>\r\n    \r\n  </script>\r\n  \r\n</body>\r\n</html>');
INSERT INTO `app_plugins` VALUES
('00C5D7F6AC075C24C26744B4C7A9350E','A5C38664EA80732ED4E9625464F1253C','app_plugins.php','<?php\r\n\r\nPluginManager::RegisterPlugin(new app_entities_plugin());\r\n\r\nclass app_entities_plugin extends PluginInterface {\r\n	protected $datos; //resultado de la consulta\r\n	\r\n	public function postUpdate($item, $datos){}\r\n	public function postInsert($item, $datos){ \r\n	    \r\n	    if (empty($datos[\'filename\']) || $datos[\'filename\']==\"\"){\r\n	        $metadata = EntityManager::GetEntityById($datos[\'id_entity\']);\r\n	        $name = $metadata[\'entity\'] .  newRandomID(4).\".php\"; \r\n	        dbupdate(\"app_plugins\",[\"id\"=>$item,\"filename\"=>$name]);\r\n	    }\r\n	    \r\n	}\r\n	public function preDuplicate($item, &$datos){ }\r\n	public function postDuplicate($item, $new_item){ }\r\n	\r\n	public function customContent($item){ \r\n		//trace (\"hola\");		\r\n	}\r\n	\r\n	public function setDefaultValues(&$datos){}\r\n	\r\n	public function preRenderform($item, &$datos){ \r\n	    /*\r\n	    if ($item == \"\" && $datos[\'id_entity\'] != \"\"){\r\n            \r\n            $metadata = EntityManager::GetEntityById($datos[\'id_entity\']);\r\n	        $name = $metadata[\'entity\'] .  newRandomID(4).\".php\"; \r\n	        $datos[\'filename\'] = $name;\r\n	    }+*/\r\n	}\r\n	public function onCustomButton($operation, $item, $datos){ \r\n		if ($operation == \"template\" ){\r\n			try{\r\n				$content = file_get_contents(\"modules/core/plugins/plugin.tpl\");\r\n				$r = [\"id\"=> $item, \"code\" => $content];\r\n				dbupdate(\"app_plugins\",$r,\"id\");\r\n				$this->showMessage(\"cargar plantilla\");\r\n				\r\n				\r\n			} catch (PDOException $e) {\r\n				$this->showMessage(\"Error al cargar la plantilla: \" . $e->getMessage());\r\n			}\r\n		}else if ($operation == \"publish\" ){\r\n			try{\r\n				\r\n				//obtenemos el modulo\r\n				$fichero = $datos[\'filename\'];\r\n				$id_entity = $datos[\'id_entity\'];\r\n				$metadata = EntityManager::GetEntityById($id_entity);\r\n				$module = EntityManager::GetModuleById($metadata[\'id_module\']);\r\n				$filename = \"modules/\".$module[\'folder\'].\"/plugins/\".$fichero;\r\n				\r\n				//guardamos en BBDD\r\n				//$r = [\"id\"=> $item, \"code\" => $datos[\'code\']];\r\n				//dbupdate(\"app_plugins\",$r,\"id\");\r\n				\r\n				//publicamos el fichero\r\n				$f = file_put_contents($filename, $datos[\'code\']);\r\n				//dump($f);\r\n				$this->showMessage(\"Plugin $fichero publicado.\");\r\n				\r\n			} catch (PDOException $e) {\r\n				$this->showMessage(\"Error al publicar el plugin: \" . $e->getMessage());\r\n			}\r\n		}else if ($operation == \"load\" ){\r\n			try{\r\n				//obtenemos el modulo\r\n				$fichero = $datos[\'filename\'];\r\n				$id_entity = $datos[\'id_entity\'];\r\n				$metadata = EntityManager::GetEntityById($id_entity);\r\n				$module = EntityManager::GetModuleById($metadata[\'id_module\']);\r\n				\r\n				$content = file_get_contents(\"modules/\".$module[\'folder\'].\"/plugins/\".$fichero);\r\n				\r\n				$r = [\"id\"=> $item,  \"code\" => $content]; //guardamos tipo fichero y su codigo\r\n				dbupdate(\"app_plugins\",$r,\"id\");\r\n				\r\n				$this->showMessage(\"Ultima version de plugin recuperada\");\r\n				\r\n			} catch (PDOException $e) {\r\n				$this->showMessage(\"Error al cargar la plantilla: \" . $e->getMessage());\r\n			}\r\n		}\r\n	}\r\n	public function postUploadFile($filedata){ $this->showMessage(\"postUploadFile\");}\r\n\r\n}\r\n',1),
('00EF943BB9ADB5A84C5E4DA8BBB19B0B','B441B8665B9EABC7B180A757E687305B','api_keys.php','<?\r\n\r\nPluginManager::RegisterPlugin(new my_new_plugin());\r\n\r\nclass my_new_plugin extends PluginInterface {\r\n	\r\n	protected $data; //use it at will between related events\r\n	\r\n	public function postUpdate($item, $datos){}\r\n	public function postInsert($item, $datos){}\r\n	public function preDuplicate($item, &$datos){ }\r\n	public function postDuplicate($item, $new_item){ }\r\n	\r\n	public function customContent($item){ 	}\r\n	\r\n	public function setDefaultValues(&$datos){  }\r\n	\r\n	public function preRenderform($item, &$datos){ \r\n\r\n		if ($item <0) $datos[\'apikey\']=newRandomId(50);\r\n\r\n	}\r\n	public function onCustomButton($operation, $item, $datos){ \r\n		\r\n	}\r\n	public function postUploadFile($filedata){ }\r\n\r\n}\r\n',1),
('05BDE6D5959F360167F8AA06143D0892','C36B36838A064DEBA5AC90B2361920CC','consultas.php','<?php\r\n\r\nPluginManager::RegisterPlugin(new consultas_plugin());\r\n\r\nclass consultas_plugin extends PluginInterface {\r\n	protected $datos; //resultado de la consulta\r\n	\r\n	public function postUpdate($item, $datos){}\r\n	public function postInsert($item, $datos){ }\r\n	public function preDuplicate($item, &$datos){ }\r\n	public function postDuplicate($item, $new_item){ }\r\n	public function customContent($item){ \r\n		$listado_html = \"\";\r\n		if ($this->datos != null){\r\n			$listado_html = generarTablaHTML($this->datos);\r\n		}\r\n		\r\n		return $listado_html;\r\n	}\r\n	public function setDefaultValues(&$datos){}\r\n	public function preRenderform($item, &$datos){ \r\n		\r\n		//$this->form->addCustomButton(\"ejecutar\", \"Ejecutar Query\", \"form\");\r\n		//$datos[\'query\']=eval(\'return \'. $datos[\"query\"] );\r\n		//$this->showMessage(\"dato modificado\");\r\n			\r\n	}\r\n	public function onCustomButton($operation, $item, $datos){ \r\n		if ($operation == \"ejecutar\" ){\r\n			try{\r\n			    \r\n			    $consulta_json = sqlToJson($datos[\"query\"]);\r\n                $consulta_reprocesada = jsonToSql($consulta_json);\r\n                //echo $consulta_reprocesada;\r\n                \r\n				$r = [\"id\" => $item, \"query\" =>$datos[\"query\"], \"query_json\" => $consulta_json ];\r\n				dbupdate(\"consultas\",$r);\r\n				\r\n				$this->datos = query($datos[\"query\"]); \r\n				$this->showMessage(\"Consulta ejecutada\");\r\n		\r\n			} catch (PDOException $e) {\r\n				$this->showMessage(\"Error en la consulta: \" . $e->getMessage());\r\n			}\r\n		}\r\n	}\r\n	public function postUploadFile($filedata){ $this->showMessage(\"postUploadFile\");}\r\n\r\n}\r\n',1),
('067892989E52F858FC6C401E75346164','D8E58E608DB593F4EA32FC4605A2065E','ventas_pedidos_lineas.php','<?php \r\n\r\nPluginManager::RegisterPlugin(new my_new_plugin());\r\n\r\nclass my_new_plugin extends PluginInterface {\r\n	\r\n	protected $data; //use it at will between related events\r\n	protected $id_pedido_padre;\r\n	\r\n	public function postUpdate($item, $datos){\r\n	   \r\n	   $this->procesarLinea($item, $datos);\r\n	   $this->UpdateOferta( $datos[\'id_pedido\']);\r\n	   \r\n	}\r\n	\r\n	public function UpdateOferta($id_pedido){\r\n	    \r\n	    $totales = subtotals(\"ventas_pedidos_lineas\", [\"total_neto\",\"total_impuestos\"], \"id_pedido\", $id_pedido);\r\n	    $oferta=[];\r\n	    //trace(\"totales \" . $id_pedido);\r\n	    //dump($totales);\r\n	    $oferta[\'id\']= $id_pedido;\r\n	    $oferta[\'total_neto\']= round($totales[\"total_neto\"],2);\r\n	    $oferta[\'total_impuestos\']= round($totales[\"total_impuestos\"],2);\r\n	    $oferta[\'importe_total\']= round($totales[\"total_neto\"],2) + round($totales[\"total_impuestos\"],2);\r\n	    \r\n	    //dump($oferta);\r\n	    dbupdate(\"ventas_pedidos\",$oferta);\r\n	    \r\n	}\r\n	\r\n	public function procesarLinea($item, $datos){\r\n	    \r\n	    $id_producto = $datos[\'id_producto\'];\r\n	    $cantidad = $datos[\'cantidad\'];\r\n	    $precio_unit = floatval($datos[\'precio\']);\r\n	    $descuento = floatval($datos[\'descuento\']);\r\n	    $pct_impuesto = floatval($datos[\'impuesto\']);\r\n	    \r\n	    \r\n	    $producto = dbgetbyid(\"productos\",$id_producto);\r\n	    //dump($producto);\r\n	    \r\n	    if ($producto!=null){\r\n	        if($precio_unit == 0) $precio_unit =  floatval($producto[\'precio\']);\r\n	        \r\n	        $id_impuesto = $producto[\'id_impuesto\'];\r\n	        if ($id_impuesto != \"\"){\r\n	            $impuesto = dbgetbyid(\"impuestos\",$id_impuesto);\r\n	            //dump($impuesto);\r\n	            $pct_impuesto = $impuesto[\'porcentaje\'];\r\n	        }\r\n	    }\r\n	    $total_neto = $precio_unit * $cantidad * (1.0- $descuento/100.0 );\r\n	    $total_impuestos = ($pct_impuesto/100.0) * $total_neto;\r\n	    \r\n	    $r = [];\r\n	    $r[\'id\'] = $item;\r\n	    $r[\'impuesto\'] = $pct_impuesto;\r\n	    $r[\'precio\'] = $precio_unit;\r\n	    $r[\'total_neto\'] = $total_neto;\r\n	    $r[\'total_impuestos\'] = $total_impuestos;\r\n	    $r[\'total_linea\'] = $total_neto + $total_impuestos;\r\n	    //dump($r);\r\n	    \r\n	    dbupdate(\"ventas_pedidos_lineas\", $r);\r\n	    \r\n	    \r\n	    \r\n	}\r\n	\r\n	public function postInsert($item, $datos){\r\n	    \r\n        $this->procesarLinea($item, $datos);\r\n	    $this->UpdateOferta($datos[\'id_pedido\']);\r\n	    \r\n	}\r\n	\r\n	public function preDelete($item){\r\n	    \r\n	    $record = dbgetbyid(\"ventas_pedidos_lineas\",$item);\r\n	    $this->id_pedido_padre = $record[\'id_pedido\'];\r\n	}\r\n	public function postDelete($item){\r\n	    \r\n	    $this->UpdateOferta($this->id_pedido_padre);\r\n	}\r\n	\r\n	public function preDuplicate($item, &$datos){ }\r\n	public function postDuplicate($item, $new_item){ }\r\n	\r\n	public function customContent($item){ 	}\r\n	\r\n	public function setDefaultValues(&$datos){  }\r\n	\r\n	public function preRenderform($item, &$datos){ \r\n	    //número de orden en el alta\r\n	    if ($item == \"\" || $item <0){\r\n	        $aux = query1(\"select coalesce(max(orden),0)+1 as orden from ventas_pedidos_lineas where id_pedido =  \".quote($datos[\'id_pedido\']));\r\n	        $datos[\'orden\'] =$aux[\'orden\'];\r\n	        \r\n	    }else { //establece el estado del registro como bloqueado o activo en función de la cabecera\r\n	        $id_pedido = $datos[\'id_pedido\'];\r\n	        $ofe = dbgetbyid(\"ventas_pedidos\",$id_pedido);\r\n	        $datos[\'status\'] = $ofe[\'status\'];\r\n	    }\r\n		\r\n	}\r\n	public function onCustomButton($operation, $item, $datos){ \r\n		\r\n	}\r\n	public function postUploadFile($file){\r\n	    $this->showMessage(\"postUploadFile\");}\r\n	    \r\n}\r\n\r\n\r\n\r\n',1),
('0689AC3729B95B3414CF7A10F629DCC8','79A1C516742E7B156ABC70C8AA6BED88','cambio_pwd_usuario.php','<?php \r\n\r\nPluginManager::RegisterPlugin(new my_new_plugin());\r\n\r\nclass my_new_plugin extends PluginInterface {\r\n	\r\n\r\n	public function onCustomButton($operation, $item, $datos){ \r\n	    \r\n	    \r\n	    if (!empty($datos[\'id_usuario\']) && !empty($datos[\'pwd\']) \r\n	        && $datos[\'pwd\']==$datos[\'pwd2\']){\r\n	            \r\n	        $new_pwd = md5($datos[\'pwd\']);\r\n	        $r = [];\r\n	        $r[\'id\'] = $datos[\'id_usuario\'];\r\n	        $r[\'pwd\'] =  $new_pwd;\r\n	        dbupdate(\"usuarios\",$r);\r\n	        $this->showMessage(\"Contraseña cambiada correctamente\");\r\n	        \r\n	    }else {\r\n	        $this->showMessage(\"Faltan datos o las contraseñas no coinciden\");\r\n	    }\r\n		\r\n	}\r\n\r\n}\r\n',1),
('07FFB4FCCCFAAB76D7B58DBE48C2BA4B','35A30F1BCCCE6D3B8D512FAEAFCD6A01','app_forms.php','<?php\r\n\r\nPluginManager::RegisterPlugin(new my_new_plugin());\r\n\r\nclass my_new_plugin extends PluginInterface {\r\n	\r\n	protected $data; //use it at will between related events\r\n	\r\n	public function postUpdate($item, $datos){ }\r\n	public function postInsert($item, $datos){ }\r\n	public function preDuplicate($item, &$datos){ }\r\n	public function postDuplicate($item, $new_item){ }\r\n	\r\n	public function customContent($item){ \r\n		//$html = \"<h3>Areas</h3>\";\r\n		//$html .= print_grid(\'44F547C359298694C704DEE48FA6BCCB\' , \"id_form\", $item,\"\");\r\n		//return $html;\r\n	}\r\n	\r\n	public function setDefaultValues(&$datos){  }\r\n	\r\n	public function preRenderform($item, &$datos){ \r\n				\r\n	}\r\n	public function onCustomButton($operation, $item, $datos){ \r\n		if ($operation == \"configure\" ){\r\n		    //dump($datos);\r\n		    //trace($item);\r\n			try{\r\n				//$r = [\"id\" => $item, \"filas\" =>$datos[\"filas\"], \"columnas\" =>$datos[\"columnas\"] ];\r\n				//dbupdate(\"app_forms\",$r);\r\n				$datos = dbgetbyid(\"app_forms\",$item);\r\n				//dump($datos);\r\n				$id_entity = $datos[\"id_entity\"];\r\n				$metadatos = EntityManager::GetEntityById($id_entity);\r\n				$nombre_entidad = $metadatos[\'entity\'];\r\n				//trace ($nombre_entidad);\r\n				\r\n				$default_width = intval(100/$datos[\"columnas\"]);\r\n				//creamos tantas areas como nos diga\r\n				for ($i=0; $i< $datos[\"filas\"]; $i++){\r\n					$area = [\"id_form\" =>$item,  \"Nombre\" =>$nombre_entidad . \" $i\", \"orden\" =>$i ];\r\n					$id_area = dbinsert(\"app_form_areas\",$area);\r\n					for ($j=0; $j< $datos[\"columnas\"]; $j++){\r\n						$seccion = [\r\n							\"id_area\" =>$id_area,  \r\n							\"Nombre\" =>$nombre_entidad . \" $i $j\", \r\n							\"label\" => $nombre_entidad . \" $i $j\",\r\n							\"width\" => $default_width,							\r\n							\"orden\" =>$j \r\n							];\r\n						$id_seccion = dbinsert(\"app_form_sections\",$seccion);\r\n						if ($i==0 && $j ==0){\r\n							//introducimos los controles de todos los campos en la primera seccion\r\n							$estructura = EntityManager::GetEstructura($nombre_entidad);\r\n							foreach($estructura as $campo){\r\n								$control = [\r\n								\"id_seccion\" =>$id_seccion,  \r\n								\"control_type\" =>\"column\", \r\n								\"dbcolumn\" => $campo[\'dbcolumn\'],					\r\n								\"orden\" =>$campo[\'orden\'],\r\n								\"width\" => \"col-100\"\r\n								];\r\n								dbinsert(\"app_user_controls\",$control);\r\n							}\r\n		\r\n						}\r\n					}\r\n				}\r\n				\r\n				\r\n			} catch (PDOException $e) {\r\n				$this->showMessage(\"Error en la consulta: \" . $e->getMessage());\r\n			}\r\n		}\r\n		\r\n	}\r\n	public function postUploadFile($filedata){ $this->showMessage(\"postUploadFile\");}\r\n\r\n}\r\n',1),
('10E08ECEBA8B6E7BA2C293C7B75261DC','8E27B7F53F2D021DE191FB39E1FE333E','app_indexes.php','<?php \r\n\r\nPluginManager::RegisterPlugin(new my_new_plugin());\r\n\r\nclass my_new_plugin extends PluginInterface {\r\n	\r\n\r\n	public function onCustomButton($operation, $item, $datos){ \r\n	    \r\n\r\n	    \r\n	    //$this->showMessage($entity_name);\r\n	    \r\n	    \r\n	    if ($operation == \"create\"){\r\n	        try{\r\n	            \r\n                $this->create_index($datos);\r\n    	        \r\n    	        $this->showMessage( \"Indice creado \". $datos[\'name\'] );\r\n    	        \r\n    	        \r\n	        } catch (PDOException $e) {\r\n				$this->showMessage(\"Error en la consulta: \" . $e->getMessage());\r\n			}\r\n	     \r\n	        \r\n	    } else if ($operation == \"list_create\"){\r\n	        \r\n	        foreach($datos as $element){\r\n	           try{\r\n                    $rel = dbgetbyid(\"app_indexes\",$element);\r\n                    $this->create_index($rel);\r\n                    \r\n        	        $this->showMessage( \"Indice creada \". $rel[\'name\'] );\r\n        	        \r\n    	        } catch (PDOException $e) {\r\n    				$this->showMessage(\"Error en la consulta: \" . $e->getMessage());\r\n    			}   \r\n	        }\r\n	        \r\n	        \r\n	    } else if ($operation == \"drop\"){\r\n	        try{\r\n                $this->drop_index($datos);\r\n                $this->showMessage( \"Indice borrado \". $datos[\'name\'] );\r\n                \r\n	        } catch (PDOException $e) {\r\n				$this->showMessage(\"Error en la consulta: \" . $e->getMessage());\r\n			}\r\n			\r\n	    } else if ($operation == \"list_drop\"){\r\n	        foreach($datos as $element){\r\n	           try{\r\n                    $rel = dbgetbyid(\"app_indexes\",$element);\r\n	       \r\n                    $this->drop_index($rel);\r\n                    $this->showMessage( \"Indice borrado \". $rel[\'name\'] );\r\n                    \r\n    	        } catch (PDOException $e) {\r\n    				$this->showMessage(\"Error en la consulta: \" . $e->getMessage());\r\n    			}\r\n	        }\r\n	    }\r\n	    \r\n		\r\n	}\r\n	\r\n	public function create_index($datos){\r\n        $metadata = EntityManager::GetEntityById($datos[\'id_entity\']);\r\n        $entity_name = $metadata[\'entity\'];\r\n        \r\n        $unique = \"\";\r\n        if ($datos[\'index_type\']==\"unique\"){\r\n            $unique = \" UNIQUE \";\r\n        }\r\n        \r\n        \r\n        $sql = \"CREATE $unique INDEX \".$datos[\'name\'];\r\n        $sql .= \" ON $entity_name  (\".$datos[\'columnas\'].\") \";\r\n\r\n        \r\n        \r\n        query($sql);\r\n        \r\n        $r = [];\r\n        $r[\'id\'] = $datos[\'id\'];\r\n        $r[\'estado\'] = 1; //activa\r\n        dbupdate(\"app_indexes\", $r);\r\n        \r\n       \r\n	}\r\n\r\n    public function drop_index($datos){\r\n        \r\n        $metadata = EntityManager::GetEntityById($datos[\'id_entity\']);\r\n        $entity_name = $metadata[\'entity\'];\r\n        \r\n        $sql = \"DROP INDEX \".$datos[\'name\'];\r\n        $sql .= \" ON $entity_name  \";\r\n        query($sql);\r\n        \r\n        $r = [];\r\n        $r[\'id\'] = $datos[\'id\'];\r\n        $r[\'estado\'] = 0; //activa\r\n        dbupdate(\"app_indexes\", $r);\r\n	}\r\n\r\n}\r\n',1),
