('45E7652790D6FCF400A398E743934706','8A7584A9F47A9E6BD168FE208A4CBA9D','app_entities.php','<?php\r\n\r\nPluginManager::RegisterPlugin(new app_entities_plugin());\r\n\r\n\r\nclass app_entities_plugin extends PluginInterface {\r\n	protected $datos; //resultado de la consulta\r\n	\r\n	public function postUpdate($item, $datos){}\r\n	public function postInsert($item, $datos){ }\r\n	public function preDuplicate($item, &$datos){\r\n	    \r\n	    $datos[\'entity\']= $datos[\'entity\'].\'_copy\';\r\n	}\r\n	public function postDuplicate($item, $new_item){ \r\n	    \r\n	    \r\n	    //duplicamos Columnas\r\n		$data = query(\"SELECT * FROM app_entity_columns where id_entity=\".quote($item));\r\n		foreach ($data as $col) {\r\n		    // code...\r\n		    $col[\'id_entity\'] = $new_item;\r\n		    $col[\'id\']=\'\';\r\n		    dbinsert(\'app_entity_columns\', $col);\r\n		}\r\n		//duplicamos Vistas\r\n		$data = query(\"SELECT * FROM app_views where id_entity=\".quote($item));\r\n		foreach ($data as $v) {\r\n		    // code...\r\n		    $v[\'id_entity\'] = $new_item;\r\n		    $v[\'id\']=\'\';\r\n		    dbinsert(\'app_views\', $v);\r\n		}\r\n		\r\n		//duplicamos javascript\r\n		$data = query(\"SELECT * FROM app_scripts where id_entity=\".quote($item));\r\n		foreach ($data as $v) {\r\n		    // code...\r\n		    $v[\'id_entity\'] = $new_item;\r\n		    $v[\'id\']=\'\';\r\n		    $v[\'estado\']=0;\r\n		    $v[\'filename\'] = \'copy_\'.$v[\'filename\'];\r\n		    dbinsert(\'app_scripts\', $v);\r\n		}\r\n		\r\n		//duplicamos plugins\r\n		$data = query(\"SELECT * FROM app_plugins where id_entity=\".quote($item));\r\n		foreach ($data as $v) {\r\n		    // code...\r\n		    $v[\'id_entity\'] = $new_item;\r\n		    $v[\'id\']=\'\';\r\n		    $v[\'estado\']=0;\r\n		    $v[\'filename\'] = \'copy_\'.$v[\'filename\'];\r\n		    dbinsert(\'app_plugins\', $v);\r\n		}\r\n		\r\n		//duplicamos formularios\r\n		$data = query(\"SELECT * FROM app_forms where id_entity=\".quote($item));\r\n		foreach ($data as $v) {\r\n		    // code...\r\n		    $v[\'id_entity\'] = $new_item;\r\n		    $old_form = $v[\'id\'];\r\n		    $v[\'id\']=\'\';\r\n		    $new_form = dbinsert(\'app_forms\', $v);\r\n		    \r\n		    $areas = query(\"SELECT * FROM app_form_areas where id_form=\".quote($old_form));\r\n    		foreach ($areas as $area) {\r\n    		    // code...\r\n    		    $area[\'id_form\'] = $new_form;\r\n    		    $old_area = $area[\'id\'];\r\n    		    $area[\'id\']=\'\';\r\n    		    $new_area = dbinsert(\'app_form_areas\', $area);\r\n    		    \r\n    		    $sections = query(\"SELECT * FROM app_form_sections where id_area=\".quote($old_area));\r\n        		foreach ($sections as $s) {\r\n        		    // code...\r\n        		    $s[\'id_area\'] = $new_area;\r\n        		    $old_section = $s[\'id\'];\r\n        		    $s[\'id\']=\'\';\r\n        		    $new_section = dbinsert(\'app_form_sections\', $s);\r\n        		    \r\n        		    $controls = query(\"SELECT * FROM app_user_controls where id_seccion=\".quote($old_section));\r\n            		foreach ($controls as $uc) {\r\n            		    // code...\r\n            		    $uc[\'id_seccion\'] = $new_section;\r\n            		    $uc[\'id\']=\'\';\r\n            		    dbinsert(\'app_user_controls\', $uc);\r\n            		}\r\n        		    \r\n        		}\r\n    		    \r\n    		}\r\n		    \r\n		}\r\n		\r\n	    \r\n	}\r\n	\r\n	public function customContent($item){ \r\n\r\n	}\r\n	\r\n	public function setDefaultValues(&$datos){}\r\n	\r\n	public function preRenderform($item, &$datos){ \r\n\r\n	}\r\n	public function onCustomButton($operation, $item, $datos){ \r\n		if ($operation == \"create\" ){\r\n			try{\r\n				$tabla = $datos[\'entity\'];\r\n				$campo_principal = $datos[\'campo_principal\'];\r\n				\r\n				$sql = \"create table $tabla ( \r\n						id char(32) not null primary KEY,\";\r\n				if ($campo_principal != \"\"){\r\n				    $sql .= \" $campo_principal varchar(100) null,\";\r\n				} \r\n		\r\n				$sql .= \" fecha_creacion TIMESTAMP DEFAULT CURRENT_TIMESTAMP,\r\n						fecha_modificacion TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP  )\";\r\n				query($sql);\r\n				\r\n				$this->showMessage(\"Tabla $tabla creada correctamente\");\r\n				\r\n			} catch (PDOException $e) {\r\n				$this->showMessage(\"Error en la consulta: \" . $e->getMessage());\r\n			}\r\n		}else if ($operation == \"create_cols\" ){\r\n			\r\n			\r\n				$estructura = EntityManager::GetEstructura($datos[\'entity\']);\r\n				$table_name = $datos[\'entity\'];\r\n				\r\n				foreach($estructura as $columna){\r\n					$col_name = $columna[\'dbcolumn\'];\r\n					$type = EntityManager::getDBtype($columna[\'type\'], $columna[\'max\']);\r\n					\r\n					$sql = \"alter table $table_name add column $col_name $type NULL\";\r\n					try{\r\n						query($sql);\r\n						\r\n					} catch (PDOException $e) {\r\n						//$this->showMessage(\"Error en la consulta: \" . $e->getMessage());\r\n					}\r\n					\r\n				}\r\n				\r\n				$this->showMessage(\"Cambios aplicados\");\r\n				\r\n			\r\n			\r\n		}else if ($operation == \"drop\" ){\r\n			try{\r\n				$tabla = $datos[\'entity\'];\r\n								\r\n				$sql = \"drop table $tabla \";\r\n				query($sql);\r\n				\r\n				$this->showMessage(\"Tabla $tabla borrada correctamente\");\r\n				\r\n			} catch (PDOException $e) {\r\n				$this->showMessage(\"Error en la consulta: \" . $e->getMessage());\r\n			}\r\n		}else if ($operation == \"load\" ){\r\n			try{\r\n				global $dbname;\r\n				\r\n				$tabla = $datos[\'entity\'];\r\n								\r\n				$sql = \"insert into app_entity_columns (id, id_entity, dbcolumn, label, type, `max`, hidden, disabled)\r\n						select HEX(RANDOM_BYTES(16)) as id,  e.id as id_entity, COLUMN_NAME , COLUMN_NAME ,\r\n						case data_type \r\n						when \'int\' then \'int\'   \r\n						when \'varchar\' then \'text\' \r\n						when \'char\' then (case when CHARACTER_MAXIMUM_LENGTH=32 THEN \'guid\' else \'text\' end) 						\r\n						when \'text\' then \'textarea\'  \r\n						when \'float\' then \'decimal\'  \r\n						when \'double\' then \'decimal\'  \r\n						when \'real\' then \'decimal\' \r\n						when \'timestamp\' then \'datetime\'\r\n						else data_type\r\n						end AS tpye, coalesce(CHARACTER_MAXIMUM_LENGTH,0) AS `max`,\r\n						(case when extra =\'auto_increment\' then 1 else 0 end) as hidden, \r\n						(case data_type when \'timestamp\' then 1 else 0 end )as disabled\r\n\r\n						from information_schema.columns AS C \r\n						inner join app_entities e on e.entity = C.table_name \r\n						where table_schema = \'$dbname\'\r\n						and C.table_name =\'$tabla\'\";\r\n				\r\n				query($sql);\r\n				\r\n				$this->showMessage(\"Columnas importadas\");\r\n				\r\n			} catch (PDOException $e) {\r\n				$this->showMessage(\"Error en la consulta: \" . $e->getMessage());\r\n			}\r\n		}\r\n	}\r\n	public function postUploadFile($filedata){ $this->showMessage(\"postUploadFile\");}\r\n\r\n}\r\n',1),
('4A902F4D83EF2610966C4D410279E6F8','C0F34C980D8AC44DAB5B7148A9669AD8','ventas_pedidos.php','<?php \r\n\r\nPluginManager::RegisterPlugin(new my_new_plugin_pedido());\r\n\r\nclass my_new_plugin_pedido extends PluginInterface {\r\n	\r\n	protected $data; //use it at will between related events\r\n	\r\n	public function postUpdate($item, $datos){ }\r\n	public function postInsert($item, $datos){ \r\n	    $datos[\'codigo\'] = nextSequence(\"ventas_pedidos\");\r\n	    $datos[\'id\']= $item;\r\n	    dbupdate(\"ventas_pedidos\", $datos);\r\n	}\r\n	public function preDuplicate($item, &$datos){ }\r\n	public function postDuplicate($item, $new_item){ \r\n	    \r\n	    //duplicamos Columnas\r\n		$data = query(\"SELECT * FROM ventas_pedidos_lineas where id_pedido=\".quote($item));\r\n		foreach ($data as $col) {\r\n		    // code...\r\n		    $col[\'id_pedido\'] = $new_item;\r\n		    $col[\'id\']=\'\';\r\n		    dbinsert(\'ventas_pedidos_lineas\', $col);\r\n		}\r\n	    \r\n	}\r\n	\r\n	public function customContent($item){ 	}\r\n	\r\n	public function setDefaultValues(&$datos){  }\r\n	\r\n	public function preRenderform($item, &$datos){ \r\n		\r\n	}\r\n	public function onCustomButton($operation, $item, $datos){ \r\n		\r\n	}\r\n	public function postUploadFile($file){ $this->showMessage(\"postUploadFile\");}\r\n\r\n}\r\n',1),
('6A439791CD14E8457BC48B03C192A427','490484A9474D03AB69738B7FC05D057C','ventas_ofertas.php','<?php \r\n\r\n\r\n\r\nPluginManager::RegisterPlugin(new my_new_plugin());	    \r\n\r\nclass my_new_plugin extends PluginInterface {\r\n	\r\n	protected $data; //use it at will between related events\r\n	\r\n	public function postUpdate($item, $datos){ \r\n	    \r\n	    \r\n	}\r\n	public function postInsert($item, $datos){ \r\n	    $datos[\'codigo\'] = nextSequence(\"ventas_ofertas\",date(\"Y\"));\r\n	    $datos[\'estado\'] =0; //borrador \r\n	    \r\n	    $hoy = new DateTime();\r\n	    $datos[\'fecha_oferta\'] = $hoy->format(\'Y-m-d\');\r\n        $hoy->add(new DateInterval(\'P30D\'));\r\n        $datos[\'valido_hasta\'] = $hoy->format(\'Y-m-d\');\r\n        \r\n	    $datos[\'id\']= $item;\r\n	    dbupdate(\"ventas_ofertas\", $datos);\r\n	}\r\n	public function preDuplicate($item, &$datos){ \r\n	    $datos[\'codigo\'] = null;\r\n	    $datos[\'status\'] = 1;\r\n	}\r\n	public function postDuplicate($item, $new_item){ \r\n	    \r\n	    //duplicamos Columnas\r\n		$data = query(\"SELECT * FROM ventas_ofertas_lineas where id_oferta=\".quote($item));\r\n		foreach ($data as $col) {\r\n		    // code...\r\n		    $col[\'id_oferta\'] = $new_item;\r\n		    $col[\'id\']=\'\';\r\n		    dbinsert(\'ventas_ofertas_lineas\', $col);\r\n		}\r\n	    \r\n	}\r\n	\r\n	public function postTransition($item, $trans){\r\n	    \r\n	    $lib = EntityManager::GetLibraryFile(\"ventas_lib.php\");\r\n\r\n        if (!empty($lib)){\r\n            include_once(\'../\'.$lib[0]);\r\n            \r\n        }\r\n        \r\n	    dump (\'class exists al ejecutar plugin :\'.class_exists(\'BL_Ventas\'));\r\n	    try{\r\n	        \r\n    	    if ($trans[\'nombre\']==\"Confirmar Pedido\"){\r\n    	        \r\n    	        BL_Ventas::Confirmar_Oferta($item);\r\n    	        \r\n    	    }\r\n	    \r\n	    }catch(Exception $err){\r\n	        echo json_encode($err);\r\n	    }\r\n	    \r\n	}\r\n	public function customContent($item){ \r\n\r\n	}\r\n	\r\n	public function setDefaultValues(&$datos){  }\r\n	\r\n	public function preRenderform($item, &$datos){ \r\n		\r\n	}\r\n	public function onCustomButton($operation, $item, $datos){ \r\n		\r\n	}\r\n	public function postUploadFile($file){ $this->showMessage(\"postUploadFile\");}\r\n\r\n}\r\n',1),
('A8E969A1A48B9B26634991C34461280E','8CD7AC1F9330314D645F44BFAD6749C4','ventas_ofertas_lineas.php','<?php \r\n\r\nPluginManager::RegisterPlugin(new my_new_plugin());\r\n\r\nclass my_new_plugin extends PluginInterface {\r\n	\r\n	protected $data; //use it at will between related events\r\n	protected $id_oferta_padre;\r\n	\r\n	public function postUpdate($item, $datos){\r\n	   \r\n	   $this->procesarLinea($item, $datos);\r\n	   $this->UpdateOferta( $datos[\'id_oferta\']);\r\n	   \r\n	}\r\n	\r\n	public function UpdateOferta($id_oferta){\r\n	    \r\n	    $totales = subtotals(\"ventas_ofertas_lineas\", [\"total_neto\",\"total_impuestos\"], \"id_oferta\", $id_oferta);\r\n	    $oferta=[];\r\n	    //trace(\"totales \" . $id_oferta);\r\n	    //dump($totales);\r\n	    $oferta[\'id\']= $id_oferta;\r\n	    $oferta[\'total_neto\']= round($totales[\"total_neto\"],2);\r\n	    $oferta[\'total_impuestos\']= round($totales[\"total_impuestos\"],2);\r\n	    $oferta[\'importe_total\']= round($totales[\"total_neto\"],2) + round($totales[\"total_impuestos\"],2);\r\n	    \r\n	    //dump($oferta);\r\n	    dbupdate(\"ventas_ofertas\",$oferta);\r\n	    \r\n	}\r\n	\r\n	public function procesarLinea($item, $datos){\r\n	    \r\n	    $id_producto = $datos[\'id_producto\'];\r\n	    $cantidad = $datos[\'cantidad\'];\r\n	    $precio_unit = floatval($datos[\'precio\']);\r\n	    $descuento = floatval($datos[\'descuento\']);\r\n	    $pct_impuesto = floatval($datos[\'impuesto\']);\r\n	    \r\n	    \r\n	    $producto = dbgetbyid(\"productos\",$id_producto);\r\n	    //dump($producto);\r\n	    \r\n	    if ($producto!=null){\r\n	        if($precio_unit == 0) $precio_unit =  floatval($producto[\'precio\']);\r\n	        \r\n	        $id_impuesto = $producto[\'id_impuesto\'];\r\n	        if ($id_impuesto != \"\"){\r\n	            $impuesto = dbgetbyid(\"impuestos\",$id_impuesto);\r\n	            //dump($impuesto);\r\n	            $pct_impuesto = $impuesto[\'porcentaje\'];\r\n	        }\r\n	    }\r\n	    $total_neto = $precio_unit * $cantidad * (1.0- $descuento/100.0 );\r\n	    $total_impuestos = ($pct_impuesto/100.0) * $total_neto;\r\n	    \r\n	    $r = [];\r\n	    $r[\'id\'] = $item;\r\n	    $r[\'impuesto\'] = $pct_impuesto;\r\n	    $r[\'precio\'] = $precio_unit;\r\n	    $r[\'total_neto\'] = $total_neto;\r\n	    $r[\'total_impuestos\'] = $total_impuestos;\r\n	    $r[\'total_linea\'] = $total_neto + $total_impuestos;\r\n	    //dump($r);\r\n	    \r\n	    dbupdate(\"ventas_ofertas_lineas\", $r);\r\n	    \r\n	    \r\n	    \r\n	}\r\n	\r\n	public function postInsert($item, $datos){\r\n	    \r\n        $this->procesarLinea($item, $datos);\r\n	    $this->UpdateOferta($datos[\'id_oferta\']);\r\n	    \r\n	}\r\n	\r\n	public function preDelete($item){\r\n	    \r\n	    $record = dbgetbyid(\"ventas_ofertas_lineas\",$item);\r\n	    $this->id_oferta_padre = $record[\'id_oferta\'];\r\n	}\r\n	public function postDelete($item){\r\n	    \r\n	    $this->UpdateOferta($this->id_oferta_padre);\r\n	}\r\n	\r\n	public function preDuplicate($item, &$datos){ }\r\n	public function postDuplicate($item, $new_item){ }\r\n	\r\n	public function customContent($item){ 	}\r\n	\r\n	public function setDefaultValues(&$datos){  }\r\n	\r\n	public function preRenderform($item, &$datos){ \r\n	    //número de orden en el alta\r\n	    if ($item == \"\" || $item <0){\r\n	        $aux = query1(\"select coalesce(max(orden),0)+1 as orden from ventas_ofertas_lineas where id_oferta =  \".quote($datos[\'id_oferta\']));\r\n	        $datos[\'orden\'] =$aux[\'orden\'];\r\n	        \r\n	    }else { //establece el estado del registro como bloqueado o activo en función de la cabecera\r\n	        $id_oferta = $datos[\'id_oferta\'];\r\n	        $ofe = dbgetbyid(\"ventas_ofertas\",$id_oferta);\r\n	        $datos[\'status\'] = $ofe[\'status\'];\r\n	    }\r\n		\r\n	}\r\n	public function onCustomButton($operation, $item, $datos){ \r\n		\r\n	}\r\n	public function postUploadFile($file){ $this->showMessage(\"postUploadFile\");}\r\n\r\n}\r\n\r\n\r\n\r\n',1),
('B212FC0A3CF1746CE632130B8AA92CBE','A68EEE98E6B4784D4DFFC8BD9102F849','app_graphics.php','<?php \r\n\r\nPluginManager::RegisterPlugin(new my_new_plugin());\r\n\r\nclass my_new_plugin extends PluginInterface {\r\n	\r\n	protected $data; //use it at will between related events\r\n	\r\n	public function postUpdate($item, $datos){ }\r\n	public function postInsert($item, $datos){ }\r\n	public function preDuplicate($item, &$datos){ }\r\n	public function postDuplicate($item, $new_item){ }\r\n	\r\n	public function customContent($item){ \r\n	   \r\n	   return print_graphic($item , \"\" , \"\", \"Titulo del grafico\");\r\n	   \r\n	    \r\n	}\r\n	\r\n	public function setDefaultValues(&$datos){  }\r\n	\r\n	public function preRenderform($item, &$datos){ \r\n		\r\n	}\r\n	public function onCustomButton($operation, $item, $datos){ \r\n		$this->showMessage(\"TEST\");\r\n	}\r\n	public function postUploadFile($file){ $this->showMessage(\"postUploadFile\");}\r\n\r\n}\r\n',1),
('C5BA920998AA1094EF844DACB6EB037A','2AAF5FB75C18B38E851D52C913976F89','app_views.php','<?php\r\n\r\nPluginManager::RegisterPlugin(new consultas_plugin());\r\n\r\nclass consultas_plugin extends PluginInterface {\r\n	protected $datos; //resultado de la consulta\r\n	\r\n	public function postUpdate($item, $datos){}\r\n	public function postInsert($item, $datos){ }\r\n	public function preDuplicate($item, &$datos){ }\r\n	public function postDuplicate($item, $new_item){ }\r\n	public function customContent($item){ \r\n		$listado_html = \"\";\r\n		if ($this->datos != null){\r\n			$listado_html = generarTablaHTML($this->datos);\r\n		}\r\n		return $listado_html;\r\n	}\r\n	public function setDefaultValues(&$datos){}\r\n	public function preRenderform($item, &$datos){ \r\n		\r\n	}\r\n	public function onCustomButton($operation, $item, $datos){ \r\n		if ($operation == \"test\" ){\r\n			try{\r\n				$r = [\"id\" => $item, \"query\" =>$datos[\"query\"] ];\r\n				dbupdate(\"app_views\",$r);\r\n				\r\n				$this->datos = query($datos[\"query\"]); \r\n				$this->showMessage(\"Consulta ejecutada\");\r\n		\r\n			} catch (PDOException $e) {\r\n				$this->showMessage(\"Error en la consulta: \" . $e->getMessage());\r\n			}\r\n		}\r\n	}\r\n	public function postUploadFile($filedata){ $this->showMessage(\"postUploadFile\");}\r\n\r\n}\r\n',1),
('CBE0B82E95E7FEDAA449B5A0F969B528','BA0C16DF30A8A623EE49338EDBEFAB38','app_entity_columns.php','<?php\r\n\r\nPluginManager::RegisterPlugin(new app_entities_plugin());\r\n\r\nclass app_entities_plugin extends PluginInterface {\r\n	protected $datos; //resultado de la consulta\r\n	\r\n	public function postUpdate($item, $datos){}\r\n	public function postInsert($item, $datos){ }\r\n	public function preDuplicate($item, &$datos){ }\r\n	public function postDuplicate($item, $new_item){ }\r\n	\r\n	public function customContent($item){ \r\n\r\n	}\r\n	\r\n	public function setDefaultValues(&$datos){}\r\n	\r\n	public function preRenderform($item, &$datos){ \r\n\r\n	}\r\n	public function onCustomButton($operation, $item, $datos){ \r\n		if ($operation == \"create\" ){\r\n			try{\r\n				$entity = EntityManager::GetEntityById($datos[\'id_entity\']);\r\n				$table_name = $entity[\'entity\'];\r\n				$col_name = $datos[\'dbcolumn\'];\r\n				$type = EntityManager::getDBtype($datos[\'type\'], $datos[\'max\']);\r\n				$default = $datos[\'value\'];\r\n				\r\n				$sql = \"alter table $table_name add column $col_name $type NULL\";\r\n				if ($default != \"\"){\r\n				    $sql .= \" DEFAULT \" . quote($default, $type);\r\n				}\r\n				//trace($sql);\r\n				query($sql);\r\n				\r\n				$this->showMessage(\"COLUMNA $table_name.$col_name CREADA correctamente\");\r\n				\r\n			} catch (PDOException $e) {\r\n				$this->showMessage(\"Error en la consulta: \" . $e->getMessage());\r\n			}\r\n		}else if ($operation == \"drop\" ){\r\n			try{\r\n				$entity = EntityManager::GetEntityById($datos[\'id_entity\']);\r\n				$table_name = $entity[\'entity\'];\r\n				$col_name = $datos[\'dbcolumn\'];\r\n				\r\n				\r\n				$sql = \"alter table $table_name drop column $col_name\";\r\n				//trace($sql);\r\n				query($sql);\r\n				\r\n				$this->showMessage(\"COLUMNA $table_name.$col_name BORRADA correctamente\");\r\n				\r\n			} catch (PDOException $e) {\r\n				$this->showMessage(\"Error en la consulta: \" . $e->getMessage());\r\n			}\r\n		}\r\n	}\r\n	public function postUploadFile($filedata){ $this->showMessage(\"postUploadFile\");}\r\n\r\n}\r\n',1),
('F8614D036A03DA49833D0E54DE68E391','383D9E6BA1659044E079B71BCE51FE19','app_form_areas.php','<?\r\n\r\nPluginManager::RegisterPlugin(new my_new_plugin());\r\n\r\nclass my_new_plugin extends PluginInterface {\r\n	\r\n	protected $data; //use it at will between related events\r\n	\r\n	public function postUpdate($item, $datos){ }\r\n	public function postInsert($item, $datos){ }\r\n	public function preDuplicate($item, &$datos){ }\r\n	public function postDuplicate($item, $new_item){ }\r\n	\r\n	public function customContent($item){ \r\n		$html = \"<h3>Secciones</h3>\";\r\n		$html .= print_grid(\'D2E616EC2D515DBC1391A839BDD6BE0A\', \"id_area\", $item,\"\");\r\n		return $html;\r\n	}\r\n	\r\n	public function setDefaultValues(&$datos){  }\r\n	\r\n	public function preRenderform($item, &$datos){ \r\n		\r\n	}\r\n	public function onCustomButton($operation, $item, $datos){ \r\n		\r\n	}\r\n	public function postUploadFile($filedata){ $this->showMessage(\"postUploadFile\");}\r\n\r\n}\r\n',1),
('FEF3304D55C34B87B9937F4575C666E0','B0D9EB0533F678EA863976D6C156CD0E','app_form_sections.php','<?\r\n\r\nPluginManager::RegisterPlugin(new my_new_plugin());\r\n\r\nclass my_new_plugin extends PluginInterface {\r\n	\r\n	protected $data; //use it at will between related events\r\n	\r\n	public function postUpdate($item, $datos){ }\r\n	public function postInsert($item, $datos){ }\r\n	public function preDuplicate($item, &$datos){ }\r\n	public function postDuplicate($item, $new_item){ }\r\n	\r\n	public function customContent($item){ \r\n		$html = \"<h3>Controles de formulario</h3>\";\r\n		$html .= print_grid(\'4CEB444996216FE37E38DE2C6C3D287A\', \"id_seccion\", $item, \"\");\r\n\r\n		return $html;\r\n	}\r\n	\r\n	public function setDefaultValues(&$datos){  }\r\n	\r\n	public function preRenderform($item, &$datos){ \r\n		\r\n	}\r\n	public function onCustomButton($operation, $item, $datos){ \r\n		\r\n	}\r\n	public function postUploadFile($filedata){ $this->showMessage(\"postUploadFile\");}\r\n\r\n}\r\n',1);
