INSERT INTO `app_report_queries` VALUES
('1913FA2E371FE3F2308ABCF7308795C2','cabecera','2025-04-22 19:03:18','2025-04-23 19:14:35','select * from ventas_ofertas where id={item}','C2DE3495A82595A48B2A0CACB8441857','unique'),
('391349FE3F000050B345942D34D97C74','lineas','2025-04-23 10:29:40','2026-06-16 08:40:46','Select lin.id, p.code as codigo, p.nombre as producto, lin.concepto, lin.cantidad, lin.precio, lin.descuento,lin.impuesto, lin.total_neto, lin.total_linea, p.imagen  \r\nfrom ventas_ofertas_lineas lin\r\nleft join productos p on lin.id_producto = p.id\r\nwhere lin.id_oferta={item}\r\norder by lin.orden','C2DE3495A82595A48B2A0CACB8441857','multiple'),
('3ECC0F843142D1062EE359F5648438DB','impuestos','2025-04-23 10:29:40','2025-08-18 09:31:29','Select lin.impuesto, sum(lin.total_impuestos) as total_impuestos\r\nfrom ventas_ofertas_lineas lin\r\nleft join productos p on lin.id_producto = p.id\r\nwhere lin.id_oferta={item}\r\ngroup by lin.impuesto\r\nhaving sum(lin.total_impuestos)<>0','C2DE3495A82595A48B2A0CACB8441857','multiple'),
('6559D21D8EF63C085F82D8F46208941F','impuestos','2025-04-23 10:29:40','2025-08-26 10:20:04','Select lin.impuesto, sum(lin.total_impuestos) as total_impuestos\r\nfrom ventas_pedidos_lineas lin\r\nleft join productos p on lin.id_producto = p.id\r\nwhere lin.id_pedido={item}\r\ngroup by lin.impuesto\r\nhaving sum(lin.total_impuestos)<>0','7F6ADFF3BC7F1488016767A96FD712DE','multiple'),
('707955DFF1D36196A63A905BA0AE21B3','empresa','2026-03-24 14:16:52','2026-04-25 19:16:25','select * from app_empresas where id = (select id_empresa from ventas_ofertas where id={item})','C2DE3495A82595A48B2A0CACB8441857','unique'),
('8A286E2917BE051EC8FD7C8FBA0D1397','cliente','2025-04-22 16:03:15','2025-04-23 19:14:45','select * from ventas_cuentas where id = (select id_cuenta from ventas_ofertas where id={item})','C2DE3495A82595A48B2A0CACB8441857','unique'),
('9DED48CC42CEFEAD16D936DB410356CF','lineas','2025-04-23 10:29:40','2025-08-26 10:19:54','Select lin.id, p.code as codigo, p.nombre as producto, lin.concepto, lin.cantidad, lin.precio, lin.descuento,lin.impuesto, lin.total_neto, lin.total_linea  \r\nfrom ventas_pedidos_lineas lin\r\nleft join productos p on lin.id_producto = p.id\r\nwhere lin.id_pedido={item}','7F6ADFF3BC7F1488016767A96FD712DE','multiple'),
