</strong></span></td>\r\n</tr>\r\n<tr data-repeat=\"lineas as linea\">\r\n<td style=\"border: 1px solid rgb(206, 212, 217);\"><span style=\"font-size: 8pt;\"><strong>{linea.codigo}</strong></span></td>\r\n<td style=\"border: 1px solid rgb(206, 212, 217);\"><span style=\"font-size: 8pt;\"><strong>{linea.producto}</strong><br>{linea.concepto}</span></td>\r\n<td style=\"border: 1px solid rgb(206, 212, 217); text-align: right;\"><span style=\"font-size: 8pt;\">{linea.cantidad}</span></td>\r\n<td style=\"border: 1px solid rgb(206, 212, 217); text-align: right;\"><span style=\"font-size: 8pt;\">{linea.precio}</span></td>\r\n<td style=\"border: 1px solid rgb(206, 212, 217); text-align: right;\"><span style=\"font-size: 8pt;\">{linea.descuento}%</span></td>\r\n<td style=\"border: 1px solid rgb(206, 212, 217); text-align: right;\"><span style=\"font-size: 8pt;\">{linea.impuesto}%</span></td>\r\n<td style=\"border: 1px solid rgb(206, 212, 217); text-align: right;\"><span style=\"font-size: 8pt;\">{linea.total_neto} &euro;</span></td>\r\n</tr>\r\n<tr>\r\n<td style=\"border: 1px none rgb(206, 212, 217);\"><span style=\"font-size: 8pt;\">&nbsp;</span></td>\r\n<td style=\"border: 1px none rgb(206, 212, 217);\"><span style=\"font-size: 8pt;\">&nbsp;</span></td>\r\n<td style=\"border: 1px none rgb(206, 212, 217); text-align: right;\"><span style=\"font-size: 8pt;\">&nbsp;</span></td>\r\n<td style=\"border: 1px none rgb(206, 212, 217); text-align: right;\"><span style=\"font-size: 8pt;\">&nbsp;</span></td>\r\n<td style=\"border: 1px solid rgb(206, 212, 217); text-align: right;\" colspan=\"2\"><span style=\"font-size: 8pt;\"><strong>Base Imponible</strong></span></td>\r\n<td style=\"border: 1px solid rgb(206, 212, 217); text-align: right;\"><span style=\"font-size: 8pt;\">{cabecera.total_neto} &euro;</span></td>\r\n</tr>\r\n<tr data-repeat=\"impuestos as impuesto\">\r\n<td style=\"border: 1px none rgb(206, 212, 217);\"><span style=\"font-size: 8pt;\">&nbsp;</span></td>\r\n<td style=\"border: 1px none rgb(206, 212, 217);\"><span style=\"font-size: 8pt;\">&nbsp;</span></td>\r\n<td style=\"border: 1px none rgb(206, 212, 217); text-align: right;\"><span style=\"font-size: 8pt;\">&nbsp;</span></td>\r\n<td style=\"border: 1px none rgb(206, 212, 217); text-align: right;\"><span style=\"font-size: 8pt;\">&nbsp;</span></td>\r\n<td style=\"border: 1px solid rgb(206, 212, 217); text-align: right;\" colspan=\"2\"><span style=\"font-size: 8pt;\"><strong>Total IVA al {impuesto.impuesto} %</strong></span></td>\r\n<td style=\"border: 1px solid rgb(206, 212, 217); text-align: right;\"><span style=\"font-size: 8pt;\">{impuesto.total_impuestos} &euro;</span></td>\r\n</tr>\r\n<tr>\r\n<td style=\"border: 1px none rgb(206, 212, 217);\"><span style=\"font-size: 8pt;\">&nbsp;</span></td>\r\n<td style=\"border: 1px none rgb(206, 212, 217);\"><span style=\"font-size: 8pt;\">&nbsp;</span></td>\r\n<td style=\"border: 1px none rgb(206, 212, 217); text-align: right;\"><span style=\"font-size: 8pt;\">&nbsp;</span></td>\r\n<td style=\"border: 1px none rgb(206, 212, 217); text-align: right;\"><span style=\"font-size: 8pt;\">&nbsp;</span></td>\r\n<td style=\"border: 1px solid rgb(206, 212, 217); text-align: right;\" colspan=\"2\"><span style=\"font-size: 8pt;\"><strong>&nbsp;Importe Total</strong></span></td>\r\n<td style=\"border: 1px solid rgb(206, 212, 217); text-align: right;\"><span style=\"font-size: 8pt;\"><strong>{cabecera.importe_total} &euro;</strong></span></td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n<p>&nbsp;</p>\r\n<table style=\"border-collapse: collapse; width: 100%;\" border=\"0\"><colgroup><col style=\"width: 99.9377%;\"></colgroup>\r\n<tbody>\r\n<tr>\r\n<td style=\"border: 1px solid rgb(206, 212, 217); background-color: #ecf0f1;\"><span style=\"font-size: 10pt;\"><strong>Notas:</strong></span></td>\r\n</tr>\r\n<tr>\r\n<td style=\"border: 1px solid rgb(206, 212, 217); font-size: 8pt;\">\r\n<p>{cabecera.notas}</p>\r\n<p>&nbsp;</p>\r\n</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</div>\r\n</div>','490484A9474D03AB69738B7FC05D057C');
