INSERT INTO `app_scripts` VALUES
('124C541483557EA60DE0CE15B26F5073','2025-04-21 17:23:32','2025-05-05 12:05:20',1,'490484A9474D03AB69738B7FC05D057C','ventas_ofertas.js','document.addEventListener(\"DOMContentLoaded\", onload);\r\n\r\n\r\nfunction onload(){\r\n    \r\n    //suscribimos eventos\r\n    var grid = document.getElementById(\'grid_lineas\');\r\n    grid.addEventListener(\'AfterInsert\',refrescarTotales);\r\n    grid.addEventListener(\'OnDelete\',refrescarTotales);\r\n    \r\n}\r\n\r\nfunction refrescarTotales(e){\r\n    \r\n    let id = MyApp.form.getFieldValue(\"id\");\r\n    \r\n    MyApp.api.retrieve(\"ventas_ofertas\",id).then(array => {\r\n        let r = array[0]; \r\n        \r\n        MyApp.form.setFieldValue(\"importe_total\", parseFloat(r.importe_total).toFixed(2) );\r\n        MyApp.form.setFieldValue(\"total_neto\", parseFloat(r.total_neto).toFixed(2) );\r\n        MyApp.form.setFieldValue(\"total_impuestos\", parseFloat(r.total_impuestos).toFixed(2) );\r\n\r\n    });\r\n    \r\n}','form'),
('70295DF2E962E20B5093655D0BF9CAAC','2025-09-23 06:55:26','2025-09-23 11:24:24',1,'20AB28F839675213390C76A55A267945','app_transiciones_proceso.js','document.addEventListener(\"DOMContentLoaded\", onload);\r\n\r\n\r\nfunction onload(){\r\n    //establecemos el prefiltro de los lookup\r\n    let id_proceso = MyApp.form.getFieldValue(\"id_proceso\" );\r\n    console.log(id_proceso);\r\n    \r\n    let obj = document.getElementById(\"id_fase_inicio\");\r\n    obj.setAttribute(\"data-field\",\"id_proceso\");\r\n    obj.setAttribute(\"data-value\",id_proceso);\r\n    \r\n    obj = document.getElementById(\"id_fase_fin\");\r\n    obj.setAttribute(\"data-field\",\"id_proceso\");\r\n    obj.setAttribute(\"data-value\",id_proceso);\r\n}\r\n\r\n','form'),
('8A5500AFBBED13AD3EC3847E2DF0FD9C','2026-03-12 18:00:59','2026-06-12 13:22:10',1,'3D87D8B6639DF0D570E9AB08F03853FD','app_proyectos_test.js','document.addEventListener(\"DOMContentLoaded\", onload);\r\n\r\n\r\nfunction onload(){\r\n    \r\n    const boton = document.querySelector(\'button[name=\"btn_modal\"]\');\r\n\r\n    // Ejemplo de uso: añadir un evento\r\n    boton.addEventListener(\'click\', on_btnclick );\r\n}\r\n\r\nfunction on_btnclick(){\r\n    abrirModal(\'./modules/ventas/code/codigo_barras.html\',\'Lector de QR\');\r\n}','form'),
('9881DF1C1029B40884A773C88966E307','2026-03-10 18:54:23','2026-03-10 18:55:24',1,'383D9E6BA1659044E079B71BCE51FE19','app_form_areas.js','document.addEventListener(\"DOMContentLoaded\", onload);\r\n\r\n\r\nfunction onload(){\r\n    //establecemos el prefiltro de los lookup\r\n    let id_form = MyApp.form.getFieldValue(\"id_form\" );\r\n    \r\n    let obj = document.getElementById(\"id_tab\");\r\n    obj.setAttribute(\"data-field\",\"id_form\");\r\n    obj.setAttribute(\"data-value\",id_form);\r\n}\r\n','form'),
('AD4C7A565384DA5DC295A6BFB2B7CAC3','2026-03-23 16:06:45','2026-03-23 21:17:49',1,'68BE6D4857B45CC219DBA380485C0FBF','keypass_clipboard.js','document.addEventListener(\"DOMContentLoaded\", onload);\r\n\r\n\r\nfunction onload(){\r\n    \r\n    const boton = document.querySelector(\'button[name=\"copiar\"]\');\r\n\r\n    // Ejemplo de uso: añadir un evento\r\n    boton.addEventListener(\'click\', on_btnclick );\r\n}\r\n\r\nfunction on_btnclick(){\r\n    \r\n    let id = MyApp.form.getFieldValue(\"id\");\r\n    \r\n    MyApp.api.retrieve(\"keypass\",id).then(array => {\r\n        let r = array[0]; \r\n        \r\n        MyApp.api.decypher(r[\'pwd\']).then(response => {\r\n            if (navigator.clipboard){\r\n                navigator.clipboard.writeText(response[\'message\']);\r\n            }else{\r\n                old_copy(response[\'message\']);\r\n            }\r\n            MyApp.ui.alert(\'Texto copiado\',\'Simple App\');\r\n        })\r\n\r\n    });\r\n    \r\n}\r\n\r\nfunction old_copy(msg){\r\n    const textArea = document.createElement(\'textarea\');\r\n    textArea.value = msg;\r\n    textArea.style.opacity = 0;\r\n    document.body.appendChild(textArea);\r\n    textArea.focus();\r\n    textArea.select();\r\n    try {\r\n      const success = document.execCommand(\'copy\');\r\n      console.log(`Text copy was ${success ? \'successful\' : \'unsuccessful\'}.`);\r\n    } catch (err) {\r\n      console.error(err.name, err.message);\r\n    }\r\n    document.body.removeChild(textArea);\r\n  }','form'),
('B20DAED33993B1517806BD3564ACF49E','2025-04-21 17:23:32','2025-08-28 11:02:03',1,'C0F34C980D8AC44DAB5B7148A9669AD8','ventas_pedido.js','document.addEventListener(\"DOMContentLoaded\", onload);\r\n\r\n\r\nfunction onload(){\r\n    \r\n    //suscribimos eventos\r\n    var grid = document.getElementById(\'grid_lineas\');\r\n    grid.addEventListener(\'AfterInsert\',refrescarTotales);\r\n    grid.addEventListener(\'OnDelete\',refrescarTotales);\r\n    \r\n}\r\n\r\nfunction refrescarTotales(e){\r\n    \r\n    let id = MyApp.form.getFieldValue(\"id\");\r\n    \r\n    MyApp.api.retrieve(\"ventas_pedidos\",id).then(array => {\r\n        let r = array[0]; \r\n        \r\n        MyApp.form.setFieldValue(\"importe_total\", parseFloat(r.importe_total).toFixed(2) );\r\n        MyApp.form.setFieldValue(\"total_neto\", parseFloat(r.total_neto).toFixed(2) );\r\n        MyApp.form.setFieldValue(\"total_impuestos\", parseFloat(r.total_impuestos).toFixed(2) );\r\n\r\n    });\r\n    \r\n}','form');
