INSERT INTO `app_tareas_proyectos` VALUES
('01A2A0509A5DF01FCDEBCE927ABCEAF8','Formularios de ACCION','2025-03-11 19:05:20','2025-03-11 23:21:20','<ul>\r\n<li>Formulario que acciona algo... subir un fichero, cambiar un password... etc. Que sea un formulario modal</li>\r\n<li>Definido como una lista de campos (como en entity) y c&oacute;digo de servidor. Duda:</li>\r\n<li>&iquest;se puede usar la entity, pero como un tipo de entidad?</li>\r\n<li>Ver notas de paneles</li>\r\n</ul>',2,'BDBAD4E456A7D9DF3BDD1E6D707371BA',0),
('085F92EF006DEF0ABE9D9DB933F8FFCE','Guardar registro desde teclado','2026-03-20 16:05:26','2026-03-20 16:05:26','<p>Usar la combinaci&oacute;n de teclas Ctrl+S para guardar el formulario</p>',2,'BDBAD4E456A7D9DF3BDD1E6D707371BA',0),
('0D87BE851DB89EE844A7DDDBC9DCBB76','LOGIN TEST EN SUBGRID','2025-02-25 10:41:54','2025-03-06 18:46:40',NULL,2,'BDBAD4E456A7D9DF3BDD1E6D707371BA',0),
('0DB3C6AC4210DDF502EE38A7555722A0','Bloqueo de registros (hacerlos no editables)','2025-04-10 14:33:41','2025-08-29 18:49:30','<p>Se podr&iacute;a crear un campo de estado para bloqueo llamado \"Estado del registro\" o \"status\" con valor true/false. A&ntilde;adirlo a todas las entidades. En el controller, tratar el editable para poner como bloqueados todos los controles.</p>\r\n<p>se ha creado un tipo de dato nuevo llamado \"status\" o \"estado del registro\" para que al a&ntilde;adir la columna a la tabla ya tenga esta gesti&oacute;n nativa.</p>\r\n<p>no s&eacute; si en el controller o en la generaci&oacute;n del formulario.</p>\r\n<p>Analizarlo.</p>\r\n<ul>\r\n<li>FormManager::Run debe recibir el modo del formulario para que en el generate_field reciba el modo del control. <span style=\"color: rgb(45, 194, 107);\">(ok)</span></li>\r\n<li>En generate_field los controles avanzados no tienen tratamiento de disabled. Ejemplo: lookup.<span style=\"color: rgb(45, 194, 107);\"> (ok)</span></li>\r\n<li>Los <strong>subgrid </strong>deben ser tambi&eacute;n bloqueables en el formulario. Tiene que haber una propiedad y pasarla al webservice para que no genere los botones de \"nuevo\", borrar y duplicar<span style=\"color: rgb(45, 194, 107);\">. (ok)</span></li>\r\n<li><span style=\"color: rgb(0, 0, 0);\">Pendiente botones del formulario para desactivar el \"guardar\" y habilitar unos botones de activaci&oacute;n/desactivaci&oacute;n Ok.</span></li>\r\n</ul>\r\n<p>&nbsp;</p>\r\n<p>&nbsp;</p>',2,'BDBAD4E456A7D9DF3BDD1E6D707371BA',0),
('1513E313514775185689C13E3796347B','BPF','2025-09-17 16:27:26','2025-10-20 17:21:35',NULL,2,'BDBAD4E456A7D9DF3BDD1E6D707371BA',0),
('2290746AE6DA5A9B34D67A2CC9D261C0','Control Lookup debe usar vista de tipo lookup. ','2025-02-12 18:29:33','2025-04-07 20:03:45','<p>En edici&oacute;n de la columna tipo lookup s&oacute;lo ser&iacute;a necesario informar la tabla, la vista har&iacute;a el resto.</p>',2,'BDBAD4E456A7D9DF3BDD1E6D707371BA',3),
('2686FC95DE4FD2DD00BD29172E9DAF63','Visor de informes PDF','2025-03-19 20:07:45','2025-03-28 17:24:21','<ul>\r\n<li>crear plantillas de informes con consultas relacionadas.<span style=\"color: rgb(22, 145, 121);\"> OK</span></li>\r\n<li>montar una p&aacute;gina espec&iacute;fica para visualizar el informe en html y bot&oacute;n con exportaci&oacute;n a pdf. <span style=\"color: rgb(22, 145, 121);\">OK</span></li>\r\n<li>asociar la plantilla a la entidad. <span style=\"color: rgb(22, 145, 121);\">OK</span></li>\r\n<li>par&aacute;metros <span style=\"color: rgb(22, 145, 121);\">OK</span>\r\n<ul>\r\n<li>plantilla (id_template)</li>\r\n<li>item (elemento a imprimir) el id del objeto que pretendemos imprimir.</li>\r\n</ul>\r\n</li>\r\n<li>montar un mecanismo para imprimir desde un formulario o desde listado. Selecci&oacute;n del informe, o bien bot&oacute;n. <span style=\"color: rgb(224, 62, 45);\">OK.</span></li>\r\n</ul>',2,'BDBAD4E456A7D9DF3BDD1E6D707371BA',3),
('29E21E49F5BF5427522C0CE16E5F348E','Definir roles y permisos','2025-03-04 19:34:22','2025-03-11 18:55:05','<ul>\r\n<li style=\"color: rgb(22, 145, 121);\"><span style=\"color: rgb(22, 145, 121);\">roles ok&nbsp;</span></li>\r\n<li style=\"color: rgb(22, 145, 121);\"><span style=\"color: rgb(22, 145, 121);\">asignaci&oacute;n roles a usuarios - ok&nbsp;</span></li>\r\n<li style=\"color: rgb(22, 145, 121);\"><span style=\"color: rgb(22, 145, 121);\">permisos por entidad asociado al rol - OK</span></li>\r\n<li style=\"color: rgb(22, 145, 121);\"><span style=\"color: rgb(22, 145, 121);\">usar permisos en grid - OK</span></li>\r\n<li style=\"color: rgb(22, 145, 121);\"><span style=\"color: rgb(22, 145, 121);\">usar permisos para men&uacute; principal ok</span></li>\r\n</ul>',2,'BDBAD4E456A7D9DF3BDD1E6D707371BA',0),
('396D872E6944FC68AFF01AD5624288C7','formularios con pestañas','2025-10-20 17:23:47','2026-03-11 11:33:12','<p>El area se asocia a un tab. Se configuran en paralelo.&nbsp;</p>\r\n<p>Pendiente filtrar por los tabs del formulario en el lookup del tab. JS en el formulario. <strong>OK</strong></p>\r\n<p></p>\r\n<p></p>',2,'BDBAD4E456A7D9DF3BDD1E6D707371BA',1),
('3C0DF5B9994D85C5BD4724589C196854','Afinar visualización de menu ','2025-04-14 22:22:24','2025-04-15 18:03:12','<p>En mobiles. En escritorio parece que va bien.</p>',2,'BDBAD4E456A7D9DF3BDD1E6D707371BA',0),
('3DBADC98E5266350F57696E9DFD3F07D','Alojar contenido CUSTOM en secciones','2025-04-15 18:04:00','2026-03-10 21:36:52','<table style=\"border-collapse: collapse; width: 100%;\" border=\"1\"><colgroup><col style=\"width: 74.7563%;\"><col style=\"width: 25.2437%;\"></colgroup>\r\n<tbody>\r\n<tr>\r\n<td>insertar contenido custom como control</td>\r\n<td><span style=\"color: #169179;\"><strong>OK</strong></span></td>\r\n</tr>\r\n<tr>\r\n<td>Al mostrar formulario, lanzar los plugin oportunos</td>\r\n<td><span style=\"color: #e03e2d;\">pdte</span></td>\r\n</tr>\r\n<tr>\r\n<td>EJEMPLO: entidad proyecto</td>\r\n<td>&nbsp;</td>\r\n</tr>\r\n</tbody>\r\n</table>',3,'BDBAD4E456A7D9DF3BDD1E6D707371BA',2),
