('B74CBB24A902D12A75C04BB643E32760','Todos los Módulos','select * from app_modules','orden','module','D15D4315C5B64BB2E6E17E0A4EBEB319','public','orden',NULL,NULL),
('B794803CD33B5BC4BC254D4D486BF13C','Todas las relaciones','Select r.id, op.color as estado_col, r.name, e1.entity as From_entity, r.field , e2.entity as To_entity, on_delete, on_update\r\nfrom app_relations r\r\nleft join app_entities e1 on r.id_entity = e1.id\r\nleft join app_entities e2 on r.id_related_entity = e2.id\r\nleft join app_optionsets op on r.estado = op.codigo and op.dominio = \'ESTADOS\'\r\n','estado, name','name','744B2497EDAF0D610DA0D599DAF7F1CF','public',NULL,NULL,NULL),
('BB4BA711F1C50B586B861ACD998D1200','Todos los pedidos','Select o.id, o.codigo, o.titulo, c.nombre as cliente, o.total_neto, o.total_impuestos, o.importe_total from ventas_pedidos as o \r\nLEFT JOIN ventas_cuentas as c on o.id_cuenta = c.id\r\n','codigo','o.codigo, c.nombre','C0F34C980D8AC44DAB5B7148A9669AD8','public',NULL,NULL,0),
('BC8594A101D50FD49BF36240E929C46A','Busqueda de proceso','select id, nombre from app_proceso_entidad','nombre','nombre','D549E0FA5CB115B1904768FC95526F79','lookup',NULL,NULL,NULL),
('BE3E1082777E8D78B7BA683B7DC507AF','Busqueda de Roles de seguridad','select id, nombre from app_roles','nombre','nombre','EB91FB64FE2288577B09EA24D0BB03C7','lookup',NULL,NULL,NULL),
('BFE077A97CF916B571A486E29A88CB2F','Ofertas Ganadas','Select opt.color, o.id, o.codigo, o.titulo, c.nombre, o.fecha_oferta, o.total_neto, o.total_impuestos, o.importe_total \r\n, opt.descripcion as Estado\r\nfrom ventas_ofertas as o \r\nLEFT JOIN ventas_cuentas as c on o.id_cuenta = c.id\r\nleft join app_optionsets opt on o.estado = opt.codigo and opt.dominio = \'ESTADO_OFERTA\'\r\nwhere o.estado =2\r\n','codigo','o.codigo, c.nombre, o.titulo','490484A9474D03AB69738B7FC05D057C','public',NULL,NULL,NULL),
('CACF6B02F98B22B0C3A837619D2E1B7B','Todos los productos','Select p.id, p.code, p.nombre, f.familia, p.ean_code, p.tipo_producto, p.precio, p.coste\r\nfrom productos p\r\nleft join familias_productos f on p.id_familia = f.id','nombre','nombre','7D2C9C0CF3B893CA6EC55DC070198D44','public',NULL,'imagen',NULL),
