('ED3D211B757011E2FB2188DAABF3875E','Tareas Terminadas','select t.id,\r\nop.color as Color,\r\nt.orden, t.nombre, \r\nop.descripcion as Estado\r\nfrom app_tareas_proyectos t\r\nleft join app_optionsets op on op.dominio = \'ESTADO_TAREA\' and t.estado_tarea = op.codigo\r\nwhere t.estado_tarea =2','estado_tarea desc, orden','nombre','BAEE82C788A6272E749AB4DE5661FEF6','public','orden',NULL,NULL),
