('FAD0DF8F2ADD9313B1A58BBE1BD9EE4F','Permisos sobre entidades','select pe.id, r.nombre as Rol, e.entity, op_r.color as Lectura, op_w.color as Escritura, op_d.color as Borrado, op_i.color as Insercion\r\nfrom app_permisos_entidad pe\r\nleft join app_roles r on pe.id_rol =r.id\r\nleft join app_entities e on pe.id_entity =e.id\r\nleft join app_optionsets op_r on op_r.dominio = \'SI_NO\' and pe.read_access = op_r.codigo\r\nleft join app_optionsets op_w on op_w.dominio = \'SI_NO\' and pe.write_access = op_w.codigo\r\nleft join app_optionsets op_d on op_d.dominio = \'SI_NO\' and pe.delete_access = op_d.codigo\r\nleft join app_optionsets op_i on op_i.dominio = \'SI_NO\' and pe.insert_access = op_i.codigo','id','id','927B4B2178AA3CFE5FCF935A7E391068','public',NULL,NULL,NULL),
('FDF338372EC2150FE735B5AF9B7D3C25','Lineas de oferta','Select lin.id, p.nombre as producto, lin.concepto, lin.cantidad, lin.precio, lin.descuento,lin.impuesto, lin.total_neto, lin.total_linea \r\nfrom ventas_ofertas_lineas lin\r\nleft join productos p on lin.id_producto = p.id\r\n\r\n\r\n','orden','concepto, p.nombre','8CD7AC1F9330314D645F44BFAD6749C4','public','orden',NULL,NULL),
