INSERT INTO `consultas` VALUES
('12B48A899E80857F736191FFD58754D3','test relacion ','select * from app_entity_columns where id_entity not in (select id from app_entities)',0,'{\n    \"select\": [\n        \"*\"\n    ],\n    \"from\": {\n        \"table\": \"app_entity_columns\",\n        \"alias\": \"\"\n    },\n    \"joins\": [],\n    \"where\": \"id_entity not in (select id from app_entities)\",\n    \"groupBy\": [],\n    \"having\": \"\",\n    \"orderBy\": [],\n    \"limit\": null,\n    \"distinct\": false\n}'),
('14890AF9A22EAC9F2DFD8C806F58968F','Update','update app_views set id_entity = (select id from app_entities where app_views.controller = app_entities.entity)',0,NULL),
('1CC6F9BBB87FADE5FB522E983A38274A','test','select e.* \r\n				from \r\n				app_roles_usuarios as ru \r\n				left join app_roles as r on ru.id_rol = r.id\r\n				left join app_permisos_entidad as pe on r.id = pe.id_rol\r\nleft join app_entities as e on pe.id_entity = e.id\r\n				where \r\n				ru.id_usuario = \'590A4A27433A5C3A85D4939810302137\'\r\nand e.id_module = \'2BAA56D57128A664AD18DF268E31E49E\'\r\nand pe.read_access = 1\r\n				group by pe.id_entity',0,'{\n    \"select\": [\n        \"e.*\"\n    ],\n    \"from\": {\n        \"table\": \"app_roles_usuarios\",\n        \"alias\": \"ru\"\n    },\n    \"joins\": [\n        {\n            \"type\": \"LEFT\",\n            \"table\": \"app_roles\",\n            \"alias\": \"r\",\n            \"on\": \"ru.id_rol = r.id\"\n        },\n        {\n            \"type\": \"LEFT\",\n            \"table\": \"app_permisos_entidad\",\n            \"alias\": \"pe\",\n            \"on\": \"r.id = pe.id_rol\"\n        },\n        {\n            \"type\": \"LEFT\",\n            \"table\": \"app_entities\",\n            \"alias\": \"e\",\n            \"on\": \"pe.id_entity = e.id\"\n        }\n    ],\n    \"where\": \"ru.id_usuario = \'590A4A27433A5C3A85D4939810302137\' and e.id_module = \'2BAA56D57128A664AD18DF268E31E49E\' and pe.read_access = 1\",\n    \"groupBy\": [\n        \"pe.id_entity\"\n    ],\n    \"having\": \"\",\n    \"orderBy\": [],\n    \"limit\": null,\n    \"distinct\": false\n}'),
('20C4539FA3B81FA443E0747CB2B8D5E4','permiso','select distinct ru.id, r.nombre, u.login\r\nfrom app_roles_usuarios as ru\r\nleft join usuarios as u on ru.id_usuario = u.id \r\nleft join app_roles as r on ru.id_rol = r.id \r\nlimit 1\r\n',0,'{\n    \"select\": [\n        \"ru.id\",\n        \"r.nombre\",\n        \"u.login\"\n    ],\n    \"from\": {\n        \"table\": \"app_roles_usuarios\",\n        \"alias\": \"ru\"\n    },\n    \"joins\": [\n        {\n            \"type\": \"LEFT\",\n            \"table\": \"usuarios\",\n            \"alias\": \"u\",\n            \"on\": \"ru.id_usuario = u.id\"\n        },\n        {\n            \"type\": \"LEFT\",\n            \"table\": \"app_roles\",\n            \"alias\": \"r\",\n            \"on\": \"ru.id_rol = r.id\"\n        }\n    ],\n    \"where\": \"\",\n    \"groupBy\": [],\n    \"having\": \"\",\n    \"orderBy\": [],\n    \"limit\": 1,\n    \"distinct\": true\n}'),
('2EA3D3DDB1CD3555EBE4F40AF02947A7','test','select * from ventas_pedidos',NULL,'{\n    \"select\": [\n        \"*\"\n    ],\n    \"from\": {\n        \"table\": \"ventas_pedidos\",\n        \"alias\": \"\"\n    },\n    \"joins\": [],\n    \"where\": \"\",\n    \"groupBy\": [],\n    \"having\": \"\",\n    \"orderBy\": [],\n    \"limit\": null,\n    \"distinct\": false\n}'),
('33D71E16D3044B1F2FE642EF2470C460','test','select * from keypass',NULL,'{\n    \"select\": [\n        \"*\"\n    ],\n    \"from\": {\n        \"table\": \"keypass\",\n        \"alias\": \"\"\n    },\n    \"joins\": [],\n    \"where\": \"\",\n    \"groupBy\": [],\n    \"having\": \"\",\n    \"orderBy\": [],\n    \"limit\": null,\n    \"distinct\": false\n}'),
('3ACAB03178E2B888ABBBBAECC4A3762F','fases','select fp.id, fp.nombre, opt_estado.descripcion, opt_estado.color from app_fases_proceso as fp LEFT JOIN app_optionsets as opt_estado on fp.tipo_fase = opt_estado.codigo and opt_estado.dominio = \'TIPO_FASE_PROCESO\'\r\nwhere id_proceso = \'F16B54E64435670CEF531775394C4628\'  order by orden asc',NULL,'{\n    \"select\": [\n        \"fp.id\",\n        \"fp.nombre\",\n        \"opt_estado.descripcion\",\n        \"opt_estado.color\"\n    ],\n    \"from\": {\n        \"table\": \"app_fases_proceso\",\n        \"alias\": \"fp\"\n    },\n    \"joins\": [\n        {\n            \"type\": \"LEFT\",\n            \"table\": \"app_optionsets\",\n            \"alias\": \"opt_estado\",\n            \"on\": \"fp.tipo_fase = opt_estado.codigo and opt_estado.dominio = \'TIPO_FASE_PROCESO\'\"\n        }\n    ],\n    \"where\": \"id_proceso = \'F16B54E64435670CEF531775394C4628\'\",\n    \"groupBy\": [],\n    \"having\": \"\",\n    \"orderBy\": [\n        \"orden asc\"\n    ],\n    \"limit\": null,\n    \"distinct\": false\n}'),
('5B8D49910DAA82CCF41DEBA549CE4425','upd vistas','update app_views set query = replace(query,\' optionsets\', \' app_optionsets\')\r\nwhere query like \'% optionsets%\'\r\n',0,'{\n    \"select\": [],\n    \"from\": {\n        \"table\": \"\",\n        \"alias\": \"\"\n    },\n    \"joins\": [],\n    \"where\": \"query like \'% optionsets%\'\",\n    \"groupBy\": [],\n    \"having\": \"\",\n    \"orderBy\": [],\n    \"limit\": null\n}'),
('741AA9ACE70BB44B75035785A503CC01','columna de tabla en seccion','select cols.dbcolumn, cols.label\r\nfrom app_entity_columns as cols\r\ninner join app_forms as f on cols.id_entity = f.id_entity\r\ninner join app_form_areas as a on f.id = a.id_form\r\ninner join app_form_sections as  s on a.id = s.id_area\r\nwhere s.id = \'BE116E97CD8680F311009F7C6524E28A\'\r\norder by cols.orden',NULL,'{\n    \"select\": [\n        \"cols.dbcolumn\",\n        \"cols.label\"\n    ],\n    \"from\": {\n        \"table\": \"app_entity_columns\",\n        \"alias\": \"cols\"\n    },\n    \"joins\": [\n        {\n            \"type\": \"INNER\",\n            \"table\": \"app_forms\",\n            \"alias\": \"f\",\n            \"on\": \"cols.id_entity = f.id_entity\"\n        },\n        {\n            \"type\": \"INNER\",\n            \"table\": \"app_form_areas\",\n            \"alias\": \"a\",\n            \"on\": \"f.id = a.id_form\"\n        },\n        {\n            \"type\": \"INNER\",\n            \"table\": \"app_form_sections\",\n            \"alias\": \"s\",\n            \"on\": \"a.id = s.id_area\"\n        }\n    ],\n    \"where\": \"s.id = \'BE116E97CD8680F311009F7C6524E28A\'\",\n    \"groupBy\": [],\n    \"having\": \"\",\n    \"orderBy\": [],\n    \"limit\": null,\n    \"distinct\": false\n}'),
('8A9E6CA6AC3661DA01C0F7D343EDFAEB','alter table','alter table app_report_templates modify template mediumtext',NULL,'{\n    \"select\": [],\n    \"from\": {\n        \"table\": \"\",\n        \"alias\": \"\"\n    },\n    \"joins\": [],\n    \"where\": \"\",\n    \"groupBy\": [],\n    \"having\": \"\",\n    \"orderBy\": [],\n    \"limit\": null\n}'),
('9C4F46A56AE8F1EE7C8CFA282F41E201','test graficas','select id_cuenta, estado, sum(total_neto) as importe , op.descripcion\r\nfrom ventas_ofertas ofe\r\ninner join app_optionsets op on ofe.estado = op.codigo and op.dominio = \'ESTADO_OFERTA\'\r\ngroup by id_cuenta, estado,op.descripcion',0,'{\n    \"select\": [\n        \"id_cuenta\",\n        \"estado\",\n        \"sum(total_neto) as importe\",\n        \"op.descripcion\"\n    ],\n    \"from\": {\n        \"table\": \"ventas_ofertas\",\n        \"alias\": \"\"\n    },\n    \"joins\": [],\n    \"where\": \"\",\n    \"groupBy\": [\n        \"id_cuenta\",\n        \"estado\",\n        \"op.descripcion\"\n    ],\n    \"having\": \"\",\n    \"orderBy\": [],\n    \"limit\": null,\n    \"distinct\": false\n}'),
('DA989922F1101376E88DC341041C51F4','Documentar BD','select * from information_schema.columns where table_schema = database()\r\nand table_name = \'app_plugins\'\r\n',0,'{\n    \"select\": [\n        \"*\"\n    ],\n    \"from\": {\n        \"table\": \"information_schema.columns\",\n        \"alias\": \"\"\n    },\n    \"joins\": [],\n    \"where\": \"table_schema = database() and table_name = \'app_plugins\'\",\n    \"groupBy\": [],\n    \"having\": \"\",\n    \"orderBy\": [],\n    \"limit\": null,\n    \"distinct\": false\n}');
